Strategy.StrategyData:
using System;
using WealthLab.Backtest;
using WealthLab.Core;
using WealthLab.Indicators;

namespace WealthScript1
{
	public class Drop3Days_LongExitAfter5Days_SignedADXMinus4_Drop3ATRsFilter_MFI14Lag4_RSI3_MFI14Ref_YRangePosYHigh : UserStrategyBase
	{
		// ===== PARAMETERS =====
		private const int DropDays = 3;                  // 3 down closes in a row
		private const int HoldBars = 6;                  // exit after 5 bars
		private const int CooldownBars = 10;             // wait this many bars after entry before re-arming

		// ===== FILTERS =====
		private const double MinPrice = 5.0;             // min $5 stock
		private const int DvLen = 20;                    // avg dollar volume lookback
		private const double MinAvgDollarVol = 500000.0; // $500k/day

		// ===== DataCruncher filters =====
		private const int AdxLen14 = 14;
		private const int LookbackBars = 4;
		private const double MinSignedADX14_Minus4 = 26.34;

		private const int AtrLen = 14;
		private const double MinDrop3ATRs = 1.0;

		// ===== MFI filters =====
		private const int Mfi14Len = 14;
		private const double MinMFI14_Lag4 = 68.92;
		private const double MinMFI14_RefBar = 53.0992;

		// ===== RSI filter =====
		private const int Rsi3Len = 3;
		private const double MaxRSI3_RefBar = 27.6931;

		// ===== Yesterday-vs-PriorDay filter =====
		private const double MaxYRangePos_YHigh = 73.0832;
		private const double MinRangeAsAtr_ForPos = 0.10;

		// ===== STATE =====
		private int _cooldownStartBar = -1;

		// ===== SERIES =====
		private TimeSeries _dollarVol;
		private TimeSeries _avgDollarVol;

		private TimeSeries _adx14;
		private TimeSeries _plusDi14;
		private TimeSeries _minusDi14;
		private TimeSeries _atr14;
		private TimeSeries _mfi14;
		private TimeSeries _rsi3;

		public override void Initialize(BarHistory bars)
		{
			// DollarVol = Close * Volume
			_dollarVol = new TimeSeries(bars.DateTimes, true);
			for (int i = 0; i < bars.Count; i++)
				_dollarVol[i] = bars.Close[i] * bars.Volume[i];

			_avgDollarVol = SMA.Series(_dollarVol, DvLen);

			// Cached indicators
			_adx14 = ADX.Series(bars, AdxLen14);
			_plusDi14 = DIPlus.Series(bars, AdxLen14);
			_minusDi14 = DIMinus.Series(bars, AdxLen14);
			_atr14 = ATR.Series(bars, AtrLen);
			_mfi14 = MFI.Series(bars, Mfi14Len);
			_rsi3 = RSI.Series(bars.Close, Rsi3Len);

			// Need enough bars for:
			// - dollar volume
			// - 3-down pattern
			// - ADX minus-4 lookback
			// - ATR-based drop filter
			// - MFI14 minus-4 lookback
			// - RSI3
			// - yesterday vs prior day calculations
			StartIndex = Math.Max(
				Math.Max(DvLen + 2, DropDays + 2),
				Math.Max(
					Math.Max(
						Math.Max(AdxLen14 + LookbackBars + 2, AtrLen + 3),
						Mfi14Len + LookbackBars + 2
					),
					Math.Max(Rsi3Len + 2, 5)
				)
			);
		}

		public override void Execute(BarHistory bars, int idx)
		{
			if (idx < StartIndex)
				return;

			// =====================================================
			// 1) EXIT: after HoldBars bars
			// =====================================================
			for (int i = OpenPositions.Count - 1; i >= 0; i--)
			{
				Position pos = OpenPositions[i];
				if (pos.PositionType != PositionType.Long)
					continue;

				int barsHeld = idx - pos.EntryBar;
				if (barsHeld >= HoldBars)
				{
					int tag = (pos.Tag is int t) ? t : -1;

					Transaction txExit = PlaceTrade(
						bars,
						TransactionType.Sell,
						OrderType.Market,
						pos.Quantity,
						tag
					);

					if (txExit != null)
						txExit.SignalName = "EXIT_5BARS";
				}
			}

			// =====================================================
			// 2) COOLDOWN
			// =====================================================
			if (_cooldownStartBar < 0 && OpenPositions.Count > 0)
			{
				Position p = OpenPositions[0];
				if (p.EntryBar >= 0)
					_cooldownStartBar = p.EntryBar;
			}

			if (_cooldownStartBar >= 0)
			{
				if (!HasOpenPosition(bars, PositionType.Long) &&
					(idx - _cooldownStartBar) >= CooldownBars)
				{
					_cooldownStartBar = -1;
				}
				else
				{
					return;
				}
			}

			// If still long, don't look for new entries
			if (HasOpenPosition(bars, PositionType.Long))
				return;

			// =====================================================
			// 3) BASIC ENTRY FILTERS
			// =====================================================
			if (bars.Close[idx] < MinPrice)
				return;

			double adv = _avgDollarVol[idx];
			if (double.IsNaN(adv) || adv < MinAvgDollarVol)
				return;

			// =====================================================
			// 4) SIGNED ADX FILTER (Minus4)
			// signal bar idx == EntryBar - 1
			// so use idx - 4
			// =====================================================
			int minus4Bar = idx - LookbackBars;
			double signedAdx14Minus4 = GetSignedAdxFromCached(minus4Bar);

			if (double.IsNaN(signedAdx14Minus4) || signedAdx14Minus4 < MinSignedADX14_Minus4)
				return;

			// =====================================================
			// 5) MFI14_Lag4 FILTER
			// signal bar idx == EntryBar - 1
			// so use idx - 4
			// =====================================================
			double mfi14Lag4 = GetMfiValue(minus4Bar);

			if (double.IsNaN(mfi14Lag4) || mfi14Lag4 < MinMFI14_Lag4)
				return;

			// =====================================================
			// 6) MFI14 reference-bar FILTER
			// MFI14_abv_53.0992 on the reference bar
			// =====================================================
			double mfi14Ref = GetMfiValue(idx);

			if (double.IsNaN(mfi14Ref) || mfi14Ref < MinMFI14_RefBar)
				return;

			// =====================================================
			// 7) RSI3 reference-bar FILTER
			// RSI3_blw_27.6931 on the reference bar
			// =====================================================
			double rsi3Ref = GetRsi3Value(idx);

			if (double.IsNaN(rsi3Ref) || rsi3Ref >= MaxRSI3_RefBar)
				return;

			// =====================================================
			// 8) YRangePos_YHigh FILTER
			// Scorecard concept:
			// signal bar = EntryBar - 1 = idx
			// yesterday   = signal bar's session
			// prior day   = session immediately before yesterday
			// =====================================================
			double yRangePosYHigh = CalcYRangePosYHigh(idx, bars);

			if (double.IsNaN(yRangePosYHigh) || yRangePosYHigh >= MaxYRangePos_YHigh)
				return;

			// =====================================================
			// 9) ENTRY PATTERN: 3 consecutive down closes ending at idx
			// =====================================================
			bool allDown = true;
			for (int k = idx - DropDays + 1; k <= idx; k++)
			{
				if (bars.Close[k] >= bars.Close[k - 1])
				{
					allDown = false;
					break;
				}
			}
			if (!allDown)
				return;

			// =====================================================
			// 10) Drop3_ATRs FILTER
			//
			// Since signal bar idx == entryBar - 1:
			// firstBar = idx - 2
			// lastBar  = idx
			//
			// Drop3_ATRs = (Open[firstBar] - Close[lastBar]) / ATR[lastBar]
			// =====================================================
			double drop3ATRs = CalcDrop3ATRs(idx, bars);

			if (double.IsNaN(drop3ATRs) || drop3ATRs < MinDrop3ATRs)
				return;

			// Anchor bar = first bar before the 3-down sequence begins
			int anchorBar = idx - DropDays;

			Transaction txEntry = PlaceTrade(
				bars,
				TransactionType.Buy,
				OrderType.Market,
				0,
				anchorBar
			);

			if (txEntry != null)
				txEntry.SignalName = "ENTRY_3DOWN_ADX14M4_MFI14L4_MFI14REF_RSI3_YRANGEPOSYHIGH_DROP3ATR";
		}

		private double GetSignedAdxFromCached(int barIndex)
		{
			if (_adx14 == null || _plusDi14 == null || _minusDi14 == null)
				return double.NaN;

			if (barIndex < 0 || barIndex >= _adx14.Count)
				return double.NaN;

			double adxVal = _adx14[barIndex];
			double plusVal = _plusDi14[barIndex];
			double minusVal = _minusDi14[barIndex];

			if (double.IsNaN(adxVal) || double.IsNaN(plusVal) || double.IsNaN(minusVal))
				return double.NaN;

			if (plusVal > minusVal)
				return adxVal;

			if (minusVal > plusVal)
				return -adxVal;

			return 0.0;
		}

		private double GetMfiValue(int barIndex)
		{
			if (_mfi14 == null)
				return double.NaN;

			if (barIndex < 0 || barIndex >= _mfi14.Count)
				return double.NaN;

			double val = _mfi14[barIndex];
			return double.IsNaN(val) ? double.NaN : val;
		}

		private double GetRsi3Value(int barIndex)
		{
			if (_rsi3 == null)
				return double.NaN;

			if (barIndex < 0 || barIndex >= _rsi3.Count)
				return double.NaN;

			double val = _rsi3[barIndex];
			return double.IsNaN(val) ? double.NaN : val;
		}

		private double CalcDrop3ATRs(int idx, BarHistory bars)
		{
			if (_atr14 == null)
				return double.NaN;

			if (idx < 2 || idx >= bars.Count)
				return double.NaN;

			int firstBar = idx - 2;
			int lastBar = idx;

			double firstOpen = bars.Open[firstBar];
			double lastClose = bars.Close[lastBar];
			double atrVal = _atr14[lastBar];

			if (double.IsNaN(firstOpen) || double.IsNaN(lastClose) || double.IsNaN(atrVal) || atrVal <= 0)
				return double.NaN;

			double drop = firstOpen - lastClose;
			return drop / atrVal;
		}

		private double CalcYRangePosYHigh(int signalIdx, BarHistory bars)
		{
			if (_atr14 == null)
				return double.NaN;

			if (signalIdx < 1 || signalIdx >= bars.Count)
				return double.NaN;

			// "Yesterday" = the session containing signalIdx
			if (!TryGetSessionHighLowClose(
				bars,
				signalIdx,
				out DateTime yDate,
				out double yHigh,
				out double yLow,
				out double yClose))
				return double.NaN;

			int yLastIdx = FindLastBarOfSession(bars, yDate);
			if (yLastIdx < 0)
				return double.NaN;

			double a = _atr14[yLastIdx];
			if (double.IsNaN(a) || a <= 0)
				return double.NaN;

			// Prior session = day before yesterday
			if (!TryGetPriorSessionHighLowBeforeDate(bars, yDate, out double pHigh, out double pLow))
				return double.NaN;

			double pRange = pHigh - pLow;
			if (pRange <= 0)
				return double.NaN;

			if (pRange < MinRangeAsAtr_ForPos * a)
				return double.NaN;

			return (yHigh - pLow) / pRange * 100.0;
		}

		private static bool TryGetSessionHighLowClose(
			BarHistory bars,
			int idx,
			out DateTime sessionDate,
			out double sessionHigh,
			out double sessionLow,
			out double sessionClose)
		{
			sessionDate = DateTime.MinValue;
			sessionHigh = double.NaN;
			sessionLow = double.NaN;
			sessionClose = double.NaN;

			if (idx < 0 || idx >= bars.Count)
				return false;

			sessionDate = bars.DateTimes[idx].Date;

			int first = idx;
			while (first > 0 && bars.DateTimes[first - 1].Date == sessionDate)
				first--;

			int last = idx;
			while (last + 1 < bars.Count && bars.DateTimes[last + 1].Date == sessionDate)
				last++;

			sessionHigh = double.MinValue;
			sessionLow = double.MaxValue;

			for (int i = first; i <= last; i++)
			{
				if (bars.High[i] > sessionHigh) sessionHigh = bars.High[i];
				if (bars.Low[i] < sessionLow) sessionLow = bars.Low[i];
			}

			sessionClose = bars.Close[last];

			if (sessionHigh == double.MinValue || sessionLow == double.MaxValue)
				return false;

			return true;
		}

		private static int FindLastBarOfSession(BarHistory bars, DateTime sessionDate)
		{
			for (int i = bars.Count - 1; i >= 0; i--)
			{
				if (bars.DateTimes[i].Date == sessionDate)
					return i;
			}

			return -1;
		}

		private static bool TryGetPriorSessionHighLowBeforeDate(
			BarHistory bars,
			DateTime targetDate,
			out double priorHigh,
			out double priorLow)
		{
			priorHigh = double.NaN;
			priorLow = double.NaN;

			int j = -1;

			for (int i = bars.Count - 1; i >= 0; i--)
			{
				if (bars.DateTimes[i].Date < targetDate)
				{
					j = i;
					break;
				}
			}

			if (j < 0)
				return false;

			DateTime priorDate = bars.DateTimes[j].Date;

			priorHigh = double.MinValue;
			priorLow = double.MaxValue;

			while (j >= 0 && bars.DateTimes[j].Date == priorDate)
			{
				double h = bars.High[j];
				double l = bars.Low[j];

				if (h > priorHigh) priorHigh = h;
				if (l < priorLow) priorLow = l;

				j--;
			}

			if (priorHigh == double.MinValue || priorLow == double.MaxValue)
				return false;

			return true;
		}
	}
}
